solution.javascript:
import { test, expect } from '@playwright/test';

test('keyboard and mouse actions', async ({ page }) => {
  await page.goto('https://demo.playwright.dev/todomvc');

  const input = page.getByPlaceholder('What needs to be done?');
  await input.click();

  // Type and press Enter
  await input.type('First Task');
  await page.keyboard.press('Enter');

  // Add another task and select all
  await input.type('Second Task');
  await page.keyboard.press('Control+A');
  await page.keyboard.press('Backspace');

  // Type new task
  await input.type('New Task');
  await input.press('Enter');

  // Hover over todo item
  const todo = page.locator('.todo-list li').first();
  await todo.hover();

  // Verify delete button becomes visible on hover
  await expect(todo.locator('.destroy')).toBeVisible();

  // Double-click to edit (if feature exists)
  const label = todo.locator('label');
  await label.dblclick();
});

